const Product = () => {
  const cakeList = [
    { id: 1, name: 'Bánh Kem Dâu', price: '250.000đ', img: '/images/p1.jpg' },
    { id: 2, name: 'Bánh Chocolate', price: '300.000đ', img: '/images/p2.jpg' },
  ];

  return (
    <section>
      <h2>Danh sách bánh mới</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '20px' }}>
        {cakeList.map(cake => (
          <div key={cake.id} className="card">
            <img src={cake.img} alt={cake.name} style={{width: '100%'}} />
            <h3>{cake.name}</h3>
            <p>{cake.price}</p>
            <button>Mua ngay</button>
          </div>
        ))}
      </div>
    </section>
  );
};
export default Product;
